  const [count, setCount] = useState(0)

  return (
    &lt;&gt;
      &lt;section id="center"&gt;
        &lt;div className="hero"&gt;
          &lt;img src={heroImg} className="base" width="170" height="179" alt="" /&gt;
          &lt;img src={reactLogo} className="framework" alt="React logo" /&gt;
          &lt;img src={viteLogo} className="vite" alt="Vite logo" /&gt;
        &lt;/div&gt;
        &lt;div&gt;
          &lt;h1&gt;Get started&lt;/h1&gt;
          &lt;p&gt;
            Edit &lt;code&gt;src/App.jsx&lt;/code&gt; and save to test &lt;code&gt;HMR&lt;/code&gt;
          &lt;/p&gt;
        &lt;/div&gt;
        &lt;button
          type="button"
          className="counter"
          onClick={() =&gt; setCount((count) =&gt; count + 1)}
        &gt;
          Count is {count}
        &lt;/button&gt;
      &lt;/section&gt;

      &lt;div className="ticks"&gt;&lt;/div&gt;

      &lt;section id="next-steps"&gt;
        &lt;div id="docs"&gt;
          &lt;svg className="icon" role="presentation" aria-hidden="true"&gt;
            &lt;use href="/icons.svg#documentation-icon"&gt;&lt;/use&gt;
          &lt;/svg&gt;
          &lt;h2&gt;Documentation&lt;/h2&gt;
          &lt;p&gt;Your questions, answered&lt;/p&gt;
          &lt;ul&gt;
            &lt;li&gt;
              &lt;a href="https://vite.dev/" target="_blank"&gt;
                &lt;img className="logo" src={viteLogo} alt="" /&gt;
                Explore Vite
              &lt;/a&gt;
            &lt;/li&gt;
            &lt;li&gt;
              &lt;a href="https://react.dev/" target="_blank"&gt;
                &lt;img className="button-icon" src={reactLogo} alt="" /&gt;
                Learn more
              &lt;/a&gt;
            &lt;/li&gt;
          &lt;/ul&gt;
        &lt;/div&gt;
        &lt;div id="social"&gt;
          &lt;svg className="icon" role="presentation" aria-hidden="true"&gt;
            &lt;use href="/icons.svg#social-icon"&gt;&lt;/use&gt;
          &lt;/svg&gt;
          &lt;h2&gt;Connect with us&lt;/h2&gt;
          &lt;p&gt;Join the Vite community&lt;/p&gt;
          &lt;ul&gt;
            &lt;li&gt;
              &lt;a href="https://github.com/vitejs/vite" target="_blank"&gt;
                &lt;svg
                  className="button-icon"
                  role="presentation"
                  aria-hidden="true"
                &gt;
                  &lt;use href="/icons.svg#github-icon"&gt;&lt;/use&gt;
                &lt;/svg&gt;
                GitHub
              &lt;/a&gt;
            &lt;/li&gt;
            &lt;li&gt;
              &lt;a href="https://chat.vite.dev/" target="_blank"&gt;
                &lt;svg
                  className="button-icon"
                  role="presentation"
                  aria-hidden="true"
                &gt;
                  &lt;use href="/icons.svg#discord-icon"&gt;&lt;/use&gt;
                &lt;/svg&gt;
                Discord
              &lt;/a&gt;
            &lt;/li&gt;
            &lt;li&gt;
              &lt;a href="https://x.com/vite_js" target="_blank"&gt;
                &lt;svg
                  className="button-icon"
                  role="presentation"
                  aria-hidden="true"
                &gt;
                  &lt;use href="/icons.svg#x-icon"&gt;&lt;/use&gt;
                &lt;/svg&gt;
                X.com
              &lt;/a&gt;
            &lt;/li&gt;
            &lt;li&gt;
              &lt;a href="https://bsky.app/profile/vite.dev" target="_blank"&gt;
                &lt;svg
                  className="button-icon"
                  role="presentation"
                  aria-hidden="true"
                &gt;
                  &lt;use href="/icons.svg#bluesky-icon"&gt;&lt;/use&gt;
                &lt;/svg&gt;
                Bluesky
              &lt;/a&gt;
            &lt;/li&gt;
          &lt;/ul&gt;
        &lt;/div&gt;
      &lt;/section&gt;

      &lt;div className="ticks"&gt;&lt;/div&gt;
      &lt;section id="spacer"&gt;&lt;/section&gt;
    &lt;/&gt;
  )
}

export default App








Example

Replace all the content of the App.jsx file with the code below:



function App() {
  return (
    &lt;div className="App"&gt;
      &lt;h1&gt;Hello World!&lt;/h1&gt;
    &lt;/div&gt;
  );
}

export default App;






Notice that the changes are visible immediately after you save the file, you do not have to reload the browser!

Here are the four foundational selectors you'll use 90% of the time.

1. The Universal Selector ( * )

This selects everything on the HTML page.



* {
  margin: 0;
  box-sizing: border-box;
}







2. The Type Selector ( element )

HTML tags matching the name directly. This is best for setting baseline styles for paragraphs, headings, or buttons.



p {
  color: #333;
  line-height: 1.5;
}







3. The Class Selector ( .class )

Any element with a matching class attribute. Uses a dot ( . ).
This is best for reusable styles you want to apply to multiple different elements.



.btn-primary {
  background: blue;
  color: white;
}

HTML: `&lt;button class="btn-primary"&gt;Click&lt;/button&gt;






4. The ID Selector ( #id )

A single element with a matching id attribute. Uses a hashtag ( # ).Unique, one-of-a-kind elements on a page (like a specific sidebar or nav).



#main-header {
  background: black;
}

HTML: `&lt;header id="main-header"&gt;...&lt;/header&gt;
